// src/lib/analyzer.ts
function isQuickWin(pr2) {
  return pr2.additions + pr2.deletions <= 100 && pr2.changedFiles <= 5;
}
function detectArea(labels, files) {
  const sourceLabel = labels.find((l2) => l2.startsWith("source: "));
  if (sourceLabel) {
    const m2 = sourceLabel.match(/source:\s*(?:core:|plugin:)(.+)/);
    if (m2) return m2[1].trim();
  }
  for (const f2 of files) {
    const m2 = f2.match(/packages\/(?:core|plugins)\/([^/]+)/);
    if (m2) return m2[1];
  }
  return null;
}
function daysSince(dateStr) {
  const ms2 = new Date(dateStr).getTime();
  if (Number.isNaN(ms2)) throw new Error(`Invalid date: ${dateStr}`);
  return Math.floor((Date.now() - ms2) / 864e5);
}
function isStale(pr2) {
  return daysSince(pr2.updatedAt) > 30;
}
function isNewThisWeek(pr2) {
  return daysSince(pr2.createdAt) <= 7;
}

